24	
25	namespace art {
26	
27	static constexpr size_t kObjectReferenceSize = 4;
28	
29	constexpr size_t ComponentSizeShiftWidth(size_t component_size) {
30	  return component_size == 1u ? 0u :
31	      component_size == 2u ? 1u :
32	          component_size == 4u ? 2u :
33	              component_size == 8u ? 3u : 0u;
34	}
35	
36	class Primitive {
37	 public:
38	  enum Type {
39	    kPrimNot = 0,
40	    kPrimBoolean,
41	    kPrimByte,
42	    kPrimChar,
43	    kPrimShort,
44	    kPrimInt,
45	    kPrimLong,
46	    kPrimFloat,
47	    kPrimDouble,
48	    kPrimVoid,
49	    kPrimLast = kPrimVoid
50	  };
51	
52	  static constexpr Type GetType(char type) {
53	    switch (type) {
54	      case 'B':
55	        return kPrimByte;
56	      case 'C':
57	        return kPrimChar;
58	      case 'D':
59	        return kPrimDouble;
60	      case 'F':
61	        return kPrimFloat;
62	      case 'I':
63	        return kPrimInt;
64	      case 'J':
65	        return kPrimLong;
66	      case 'S':
67	        return kPrimShort;
68	      case 'Z':
69	        return kPrimBoolean;
70	      case 'V':
71	        return kPrimVoid;
72	      default:
73	        return kPrimNot;
74	    }
75	  }
76	
77	  static constexpr size_t ComponentSizeShift(Type type) {
78	    switch (type) {
79	      case kPrimVoid:
80	      case kPrimBoolean:
81	      case kPrimByte:    return 0;
82	      case kPrimChar:
83	      case kPrimShort:   return 1;
84	      case kPrimInt:
85	      case kPrimFloat:   return 2;
86	      case kPrimLong:
87	      case kPrimDouble:  return 3;
88	      case kPrimNot:     return ComponentSizeShiftWidth(kObjectReferenceSize);
89	    }
90	    LOGF("Invalid type %d\n", static_cast<int>(type));
91	    UNREACHABLE();
92	  }
93	
94	  static constexpr size_t ComponentSize(Type type) {
95	    switch (type) {
96	      case kPrimVoid:    return 0;
97	      case kPrimBoolean:
98	      case kPrimByte:    return 1;
99	      case kPrimChar:
100	      case kPrimShort:   return 2;
101	      case kPrimInt:
102	      case kPrimFloat:   return 4;
103	      case kPrimLong:
104	      case kPrimDouble:  return 8;
105	      case kPrimNot:     return kObjectReferenceSize;
106	    }
107	    LOGF("Invalid type %d\n", static_cast<int>(type));
108	    UNREACHABLE();
109	  }
110	
111	  static const char* Descriptor(Type type) {
112	    switch (type) {
113	      case kPrimBoolean:
114	        return "Z";
115	      case kPrimByte:
116	        return "B";
117	      case kPrimChar:
118	        return "C";
119	      case kPrimShort:
120	        return "S";
121	      case kPrimInt:
122	        return "I";
123	      case kPrimFloat:
124	        return "F";
125	      case kPrimLong:
126	        return "J";
127	      case kPrimDouble:
128	        return "D";
129	      case kPrimVoid:
130	        return "V";
131	      default:
132	        LOGF("Primitive char conversion on invalid type %d\n", static_cast<int>(type));
133	        return nullptr;
134	    }
135	  }
136	
137	  static const char* PrettyDescriptor(Type type);
138	
139	  // Returns the descriptor corresponding to the boxed type of |type|.
140	  static const char* BoxedDescriptor(Type type);
141	
142	  // Returns true if |type| is an numeric type.
143	  static constexpr bool IsNumericType(Type type) {
144	    switch (type) {
145	      case Primitive::Type::kPrimNot: return false;
146	      case Primitive::Type::kPrimBoolean: return false;
147	      case Primitive::Type::kPrimByte: return true;
148	      case Primitive::Type::kPrimChar: return true;
149	      case Primitive::Type::kPrimShort: return true;
150	      case Primitive::Type::kPrimInt: return true;
151	      case Primitive::Type::kPrimLong: return true;
152	      case Primitive::Type::kPrimFloat: return true;
153	      case Primitive::Type::kPrimDouble: return true;
154	      case Primitive::Type::kPrimVoid: return false;
155	    }
156	    LOGF("Invalid type %d\n", static_cast<int>(type));
157	    UNREACHABLE();
158	  }
159	
160	  // Return trues if |type| is a signed numeric type.
161	  static constexpr bool IsSignedNumericType(Type type) {
162	    switch (type) {
163	      case Primitive::Type::kPrimNot: return false;
164	      case Primitive::Type::kPrimBoolean: return false;
165	      case Primitive::Type::kPrimByte: return true;
166	      case Primitive::Type::kPrimChar: return false;
167	      case Primitive::Type::kPrimShort: return true;
168	      case Primitive::Type::kPrimInt: return true;
169	      case Primitive::Type::kPrimLong: return true;
170	      case Primitive::Type::kPrimFloat: return true;
171	      case Primitive::Type::kPrimDouble: return true;
172	      case Primitive::Type::kPrimVoid: return false;
173	    }
174	    LOGF("Invalid type %d\n", static_cast<int>(type));
175	    UNREACHABLE();
176	  }
177	
178	  // Returns the number of bits required to hold the largest
179	  // positive number that can be represented by |type|.
180	  static constexpr size_t BitsRequiredForLargestValue(Type type) {
181	    switch (type) {
182	      case Primitive::Type::kPrimNot: return 0u;
183	      case Primitive::Type::kPrimBoolean: return 1u;
184	      case Primitive::Type::kPrimByte: return 7u;
185	      case Primitive::Type::kPrimChar: return 16u;
186	      case Primitive::Type::kPrimShort: return 15u;
187	      case Primitive::Type::kPrimInt: return 31u;
188	      case Primitive::Type::kPrimLong: return 63u;
189	      case Primitive::Type::kPrimFloat: return 128u;
190	      case Primitive::Type::kPrimDouble: return 1024u;
191	      case Primitive::Type::kPrimVoid: return 0u;
192	    }
193	  }
194	
195	  static bool Is64BitType(Type type) {
196	    return type == kPrimLong || type == kPrimDouble;
197	  }
198	
199	};
200	
201	}  // namespace art
