425	std::string DexFile::GetMethodParametersDescriptor(dex::ProtoId& proto_id) {
426	    if (!proto_id.IsValid()) {
427	        dumpReason(proto_id.Ptr());
428	        return "(...)";
429	    }
430	
431	    std::string result;
432	    if (proto_id.parameters_off()) {
433	        dex::TypeList list = data_begin() + proto_id.parameters_off();
434	        api::MemoryRef ref = list.list();
435	        result.append("(");
436	        for (uint32_t i = 0; i < list.size(); ++i) {
437	            dex::TypeIndex idx(ref.value16Of(i * SIZEOF(TypeItem)));
438	            dex::TypeId type_id = GetTypeId(idx);
439	            result.append(GetTypeDescriptor(type_id, "V"));
440	        }
441	        result.append(")");
442	        return result;
443	    }
444	    return "()";
445	}
