447	std::string DexFile::PrettyMethodParameters(dex::MethodId& method_id) {
448	    if (!method_id.IsValid()) {
449	        dumpReason(method_id.Ptr());
450	        return "(...)";
451	    }
452	
453	    std::string result;
454	    dex::ProtoId proto_id = GetMethodPrototype(method_id);
455	    if (proto_id.parameters_off()) {
456	        dex::TypeList list = data_begin() + proto_id.parameters_off();
457	        api::MemoryRef ref = list.list();
458	        result.append("(");
459	        for (uint32_t i = 0; i < list.size(); ++i) {
460	            if (i > 0) {
461	                result.append(", ");
462	            }
463	            dex::TypeIndex idx(ref.value16Of(i * SIZEOF(TypeItem)));
464	            dex::TypeId type_id = GetTypeId(idx);
465	            std::string tmp;
466	            AppendPrettyDescriptor(GetTypeDescriptor(type_id, "V"), &tmp);
467	            result.append(tmp);
468	        }
469	        result.append(")");
470	        return result;
471	    }
472	    return "()";
473	}
