518	        if (file) {
519	            LOGD("[%" PRIx64 ", %" PRIx64 ") %08" PRIx64 " %s [EMPTY]\n", file->begin(), file->end(),
520	                    file->offset(), file->name().c_str());
521	        } else {
522	            LoadBlock* block = CoreApi::FindLoadBlock(vaddr, false);
523	            if (block) {
524	                LOGD("[%" PRIx64 ", %" PRIx64 ") %s [EMPTY]\n", block->vaddr(), block->vaddr() + block->memsz(), GetLocation().c_str());
525	            }
526	        }
527	    }
528	}
