34	
35	void CompactDexFile::CodeItem::DecodeFields() {
36	    insns_count_ = insns_count_and_flags() >> CompactDexFile::CodeItem::kInsnsSizeShift;
37	    num_regs_ = (fields() >> CompactDexFile::CodeItem::kRegistersSizeShift) & 0xF;
38	    ins_size_ = (fields() >> CompactDexFile::CodeItem::kInsSizeShift) & 0xF;
39	    out_regs_ = (fields() >> CompactDexFile::CodeItem::kOutsSizeShift) & 0xF;
40	    tries_size_ = (fields() >> CompactDexFile::CodeItem::kTriesSizeSizeShift) & 0xF;
41	
42	    if ((insns_count_and_flags() & CompactDexFile::CodeItem::kFlagPreHeaderCombined) != 0x0) {
43	        api::MemoryRef preheader = Ptr();
44	        preheader.copyRef(this);
45	        if ((insns_count_and_flags() & CompactDexFile::CodeItem::kFlagPreHeaderInsnsSize) != 0x0) {
46	            preheader.MovePtr(-sizeof(uint16_t));
47	            insns_count_ += static_cast<uint32_t>(preheader.value16Of());
48	            preheader.MovePtr(-sizeof(uint16_t));
49	            insns_count_ += static_cast<uint32_t>(preheader.value16Of()) << 16;
50	        }
51	
52	        if ((insns_count_and_flags() & CompactDexFile::CodeItem::kFlagPreHeaderRegistersSize) != 0x0) {
53	            preheader.MovePtr(-sizeof(uint16_t));
54	            num_regs_ += preheader.value16Of();
55	        }
56	
57	        if ((insns_count_and_flags() & CompactDexFile::CodeItem::kFlagPreHeaderInsSize) != 0x0) {
58	            preheader.MovePtr(-sizeof(uint16_t));
59	            ins_size_ += preheader.value16Of();
60	        }
61	
62	        if ((insns_count_and_flags() & CompactDexFile::CodeItem::kFlagPreHeaderOutsSize) != 0x0) {
63	            preheader.MovePtr(-sizeof(uint16_t));
64	            out_regs_ += preheader.value16Of();
65	        }
66	
67	        if ((insns_count_and_flags() & CompactDexFile::CodeItem::kFlagPreHeaderTriesSize) != 0x0) {
68	            preheader.MovePtr(-sizeof(uint16_t));
69	            tries_size_ += preheader.value16Of();
70	        }
71	    }
72	    num_regs_ += ins_size_;
73	    code_offset_ = OFFSET(CompactDexFile_CodeItem, insns_);
74	}
