37	int MethodCommand::prepare(int argc, char* const argv[]) {
38	    if (!CoreApi::IsReady()
39	            || !Android::IsSdkReady()
40	            || !(argc > 1))
41	        return Command::FINISH;
42	
43	    options.instpc = 0x0;
44	    options.dump_opt = METHOD_DUMP_NAME;
45	    options.verbose = false;
46	    options.count = 0;
47	    options.pc = 0x0;
48	    options.dexpc = 0x0;
49	
50	    int opt;
51	    int option_index = 0;
52	    optind = 0; // reset
53	    static struct option long_options[] = {
54	        {"dex-dump",    no_argument,       0,  1 },
55	        {"oat-dump",    no_argument,       0,  2 },
56	        {"pc",          required_argument, 0,  3 },
57	        {"inst",        required_argument, 0, 'i'},
58	        {"num",         required_argument, 0, 'n'},
59	        {"verbose",     no_argument,       0, 'v'},
60	        {"binary",      no_argument,       0, 'b'},
61	        {"search",      required_argument, 0, 's'},
62	        {0,             0,                 0,  0 },
63	    };
64	
65	    while ((opt = getopt_long(argc, argv, "i:n:012bvs:",
66	                long_options, &option_index)) != -1) {
67	        switch (opt) {
68	            case 'i':
69	                options.instpc = Utils::atol(optarg);
70	                break;
71	            case 'n':
72	                options.count = std::atoi(optarg);
73	                break;
74	            case 1:
75	                options.dump_opt |= METHOD_DUMP_DEXCODE;
76	                break;
77	            case 2:
78	                options.dump_opt |= METHOD_DUMP_OATCODE;
79	                break;
80	            case 3:
81	                options.pc = Utils::atol(optarg);
82	                break;
83	            case 'v':
84	                options.verbose = true;
85	                break;
86	            case 'b':
87	                options.dump_opt |= METHOD_DUMP_BINARY;
88	                break;
89	            case 's':
90	                options.dexpc = Utils::atol(optarg);
91	                break;
92	        }
93	    }
94	    options.optind = optind;
95	
96	    if (options.optind >= argc && !options.dexpc) {
97	        usage();
98	        return Command::FINISH;
99	    }
