22	void AppendPrettyDescriptor(const char* descriptor, std::string* result) {
23	  // Count the number of '['s to get the dimensionality.
24	  const char* c = descriptor;
25	  size_t dim = 0;
26	  while (*c == '[') {
27	    dim++;
28	    c++;
29	  }
30	
31	  // Reference or primitive?
32	  bool primitive = false;
33	  if (*c == 'L') {
34	    // "[[La/b/C;" -> "a.b.C[][]".
35	    c++;  // Skip the 'L'.
36	  } else {
37	    primitive = true;
38	    // "[[B" -> "byte[][]".
39	    switch (*c) {
40	      case 'B':
41	        c = "byte";
42	        break;
43	      case 'C':
44	        c = "char";
45	        break;
46	      case 'D':
47	        c = "double";
48	        break;
49	      case 'F':
50	        c = "float";
51	        break;
52	      case 'I':
53	        c = "int";
54	        break;
55	      case 'J':
56	        c = "long";
57	        break;
58	      case 'S':
59	        c = "short";
60	        break;
61	      case 'Z':
62	        c = "boolean";
63	        break;
64	      case 'V':
65	        c = "void";
66	        break;  // Used when decoding return types.
67	      default: result->append(descriptor); return;
68	    }
69	  }
70	
71	  // At this point, 'c' is a string of the form "fully/qualified/Type;" or
72	  // "primitive". In the former case, rewrite the type with '.' instead of '/':
73	  std::string temp(c);
74	  if (!primitive) {
75	    std::replace(temp.begin(), temp.end(), '/', '.');
76	    // ...and remove the semicolon:
77	    if (temp.back() == ';') {
78	      temp.pop_back();
79	    }
80	  }
81	  result->append(temp);
82	
83	  // Finally, add 'dim' "[]" pairs:
84	  for (size_t i = 0; i < dim; ++i) {
85	    result->append("[]");
86	  }
87	}
88	
89	void AppendPrettyDescriptor(const char* descriptor, std::string* result, const char* def) {
90	  char c = descriptor[0];
91	  switch (c) {
92	    case '[':
93	    case 'L':
94	    case 'Z':
95	    case 'C':
96	    case 'F':
97	    case 'D':
98	    case 'B':
99	    case 'S':
100	    case 'I':
101	    case 'J':
102	    case 'V':
103	      AppendPrettyDescriptor(descriptor, result);
104	      break;
105	    default:
106	      AppendPrettyDescriptor(def, result);
107	      break;
108	  }
109	}
110	
111	std::string DotToDescriptor(const char* class_name) {
112	  std::string descriptor(class_name);
113	  std::replace(descriptor.begin(), descriptor.end(), '.', '/');
114	  if (descriptor.length() > 0 && descriptor[0] != '[') {
115	    descriptor = "L" + descriptor + ";";
116	  }
117	  return descriptor;
118	}
