23	std::string PrettyJavaAccessFlags(uint32_t access_flags) {
24	  std::string result;
25	  if ((access_flags & kAccPublic) != 0) {
26	    result += "public ";
27	  }
28	  if ((access_flags & kAccProtected) != 0) {
29	    result += "protected ";
30	  }
31	  if ((access_flags & kAccPrivate) != 0) {
32	    result += "private ";
33	  }
34	  if ((access_flags & kAccFinal) != 0) {
35	    result += "final ";
36	  }
37	  if ((access_flags & kAccStatic) != 0) {
38	    result += "static ";
39	  }
40	  if ((access_flags & kAccAbstract) != 0) {
41	    result += "abstract ";
42	  }
43	  if ((access_flags & kAccSynchronized) != 0) {
44	    result += "synchronized ";
45	  }
46	  return result;
47	}
48	
49	std::string PrettyFieldAccessFlags(uint32_t access_flags) {
50	  std::string result = PrettyJavaAccessFlags(access_flags);
51	  if ((access_flags & kAccTransient) != 0) {
52	    result += "transient ";
53	  }
54	  if ((access_flags & kAccVolatile) != 0) {
55	    result += "volatile ";
56	  }
57	  return result;
58	}
59	
60	std::string PrettyClassAccessFlags(uint32_t access_flags) {
61	  std::string result = PrettyJavaAccessFlags(access_flags);
62	  if ((access_flags & kAccClassIsProxy) != 0) {
63	    result += "proxy ";
64	  }
65	  if ((access_flags & kAccInterface) != 0) {
66	    result += "interface ";
67	  }
68	  if ((access_flags & kAccEnum) != 0) {
69	    result += "enum ";
70	  }
71	  return result;
72	}
73	
74	std::string PrettyMethodAccessFlags(uint32_t access_flags) {
75	  std::string result = PrettyJavaAccessFlags(access_flags);
76	  if ((access_flags & kAccNative) != 0) {
77	    result += "native ";
78	  }
79	  // IsDefaultConflicting
80	  static constexpr uint32_t kMask = kAccIntrinsic | kAccCopied | kAccAbstract | kAccDefault;
81	  static constexpr uint32_t kValue = kAccCopied | kAccAbstract | kAccDefault;
82	  if ((access_flags & kMask) == kValue) {
83	    result += "conflicting ";
84	  }
85	  return result;
86	}
