21	
22	void ConvertUtf16ToModifiedUtf8(char* utf8_out, size_t byte_count,
23	                                const uint16_t* utf16_in, size_t char_count) {
24	  if (LIKELY(byte_count == char_count)) {
25	    // Common case where all characters are ASCII.
26	    const uint16_t *utf16_end = utf16_in + char_count;
27	    for (const uint16_t *p = utf16_in; p < utf16_end;) {
28	      *utf8_out++ = static_cast<char>(*p++);
29	    }
30	    return;
31	  }
32	
33	  // String contains non-ASCII characters.
34	  while (char_count--) {
35	    const uint16_t ch = *utf16_in++;
36	    if (ch > 0 && ch <= 0x7f) {
37	      *utf8_out++ = ch;
38	    } else {
39	      // Char_count == 0 here implies we've encountered an unpaired
40	      // surrogate and we have no choice but to encode it as 3-byte UTF
41	      // sequence. Note that unpaired surrogates can occur as a part of
42	      // "normal" operation.
43	      if ((ch >= 0xd800 && ch <= 0xdbff) && (char_count > 0)) {
44	        const uint16_t ch2 = *utf16_in;
45	
46	        // Check if the other half of the pair is within the expected
47	        // range. If it isn't, we will have to emit both "halves" as
48	        // separate 3 byte sequences.
49	        if (ch2 >= 0xdc00 && ch2 <= 0xdfff) {
50	          utf16_in++;
51	          char_count--;
52	          const uint32_t code_point = (ch << 10) + ch2 - 0x035fdc00;
53	          *utf8_out++ = (code_point >> 18) | 0xf0;
54	          *utf8_out++ = ((code_point >> 12) & 0x3f) | 0x80;
55	          *utf8_out++ = ((code_point >> 6) & 0x3f) | 0x80;
56	          *utf8_out++ = (code_point & 0x3f) | 0x80;
57	          continue;
58	        }
59	      }
60	
61	      if (ch > 0x07ff) {
62	        // Three byte encoding.
63	        *utf8_out++ = (ch >> 12) | 0xe0;
64	        *utf8_out++ = ((ch >> 6) & 0x3f) | 0x80;
65	        *utf8_out++ = (ch & 0x3f) | 0x80;
66	      } else /*(ch > 0x7f || ch == 0)*/ {
67	        // Two byte encoding.
68	        *utf8_out++ = (ch >> 6) | 0xc0;
69	        *utf8_out++ = (ch & 0x3f) | 0x80;
70	      }
71	    }
72	  }
73	}
74	
75	size_t CountUtf8Bytes(const uint16_t* chars, size_t char_count) {
76	  size_t result = 0;
77	  const uint16_t *end = chars + char_count;
78	  while (chars < end) {
79	    const uint16_t ch = *chars++;
80	    if (LIKELY(ch != 0 && ch < 0x80)) {
81	      result++;
82	      continue;
83	    }
84	    if (ch < 0x800) {
85	      result += 2;
86	      continue;
87	    }
88	    if (ch >= 0xd800 && ch < 0xdc00) {
89	      if (chars < end) {
90	        const uint16_t ch2 = *chars;
91	        // If we find a properly paired surrogate, we emit it as a 4 byte
92	        // UTF sequence. If we find an unpaired leading or trailing surrogate,
93	        // we emit it as a 3 byte sequence like would have done earlier.
94	        if (ch2 >= 0xdc00 && ch2 < 0xe000) {
95	          chars++;
96	          result += 4;
97	          continue;
98	        }
99	      }
100	    }
101	    result += 3;
102	  }
103	  return result;
104	}
